"use client";

import {
  memo,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_COMMENT_THREAD_LABELS,
  type Comment,
  type CommentThread01Handle,
  type CommentThread01Props,
  type CommentThreadLabels,
} from "./types";
import { useCommentState } from "./hooks/use-comment-state";
import { CommentNode } from "./parts/comment-node";
import {
  CommentComposer,
  type CommentComposerHandle,
} from "./parts/comment-composer";
import { CommentEmptyState } from "./parts/comment-empty-state";
import { defaultRelativeTime } from "./lib/format-time";

interface CommentThread01InnerProps extends CommentThread01Props {
  ref?: React.Ref<CommentThread01Handle>;
}

function genTempId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return `temp-${crypto.randomUUID()}`;
  }
  return `temp-${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

function CommentThread01Inner(props: CommentThread01InnerProps) {
  const {
    comments: initialComments,
    variant = "default",
    currentUser,
    maxDepth = 2,
    indentPx = 24,
    bodyMaxLines: bodyMaxLinesProp,
    composerMinRows = 1,
    composerMaxRows = 6,
    submitOnEnter = true,
    pageSize = 10,
    subscribe,
    onSubscribeDelta,
    onAddComment,
    onLikeComment,
    onDeleteComment,
    onReportComment,
    onLoadMore,
    commentActions,
    renderNode,
    renderViewReplies,
    renderComposer,
    composerEmptyState,
    emptyState,
    labels: labelsProp,
    className,
    composerClassName,
    nodeClassName,
    ref,
  } = props;

  const bodyMaxLines = bodyMaxLinesProp ?? (variant === "compact" ? 2 : 4);

  const labels = useMemo<
    Required<Omit<CommentThreadLabels, "formatRelativeTime">>
  >(
    () => ({ ...DEFAULT_COMMENT_THREAD_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const format = useMemo(
    () => labelsProp?.formatRelativeTime ?? defaultRelativeTime,
    [labelsProp?.formatRelativeTime],
  );

  const { comments, dispatch } = useCommentState({
    initialComments,
    subscribe,
    onSubscribeDelta,
  });

  const [replyParentId, setReplyParentId] = useState<string | null>(null);
  const replyTriggerRef = useRef<HTMLElement | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(initialComments.length === pageSize);
  const composerRef = useRef<CommentComposerHandle | null>(null);

  // Stable refs for the imperative handle.
  const commentsRef = useRef<Comment[]>(comments);
  useEffect(() => {
    commentsRef.current = comments;
  });

  useImperativeHandle(
    ref,
    () => ({
      focusComposer: () => composerRef.current?.focus(),
      openReply: (parentId: string) => setReplyParentId(parentId),
      getCurrentComments: () => commentsRef.current,
      reset: (next: Comment[]) => dispatch({ kind: "reset", next }),
      dispatch,
    }),
    // dispatch is stable; setReplyParentId is stable; refs handle the rest.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  // ─── Handlers ─────────────────────────────────────────────────────────────

  const handleLike = useCallback(
    (commentId: string, nextLiked: boolean) => {
      dispatch({ kind: "like-toggle", commentId, nextLiked });
      onLikeComment?.(commentId, nextLiked);
    },
    [dispatch, onLikeComment],
  );

  const handleDelete = useCallback(
    (commentId: string) => {
      dispatch({ kind: "remove", commentId });
      onDeleteComment?.(commentId);
    },
    [dispatch, onDeleteComment],
  );

  const handleReport = useCallback(
    (commentId: string) => {
      onReportComment?.(commentId);
    },
    [onReportComment],
  );

  const submitTopLevel = useCallback(
    async (content: string) => {
      if (!currentUser) return;
      const tempId = genTempId();
      const tempComment: Comment = {
        id: tempId,
        author: {
          id: currentUser.id,
          name: currentUser.name,
          avatar: currentUser.avatar,
        },
        content,
        createdAt: new Date(),
        likes: 0,
        isLiked: false,
        replies: [],
      };
      dispatch({ kind: "add", comment: tempComment });
      const result = await onAddComment?.(content);
      if (result && typeof result === "object") {
        dispatch({ kind: "swap-temp", tempId, real: result });
      }
    },
    [currentUser, dispatch, onAddComment],
  );

  const submitReply = useCallback(
    async (content: string, parentId: string) => {
      if (!currentUser) return;
      const tempId = genTempId();
      const tempComment: Comment = {
        id: tempId,
        author: {
          id: currentUser.id,
          name: currentUser.name,
          avatar: currentUser.avatar,
        },
        content,
        createdAt: new Date(),
        likes: 0,
        isLiked: false,
        replies: [],
      };
      dispatch({ kind: "add", comment: tempComment, parentId });
      const result = await onAddComment?.(content, parentId);
      if (result && typeof result === "object") {
        dispatch({ kind: "swap-temp", tempId, real: result });
      }
      // Close inline composer + restore focus to the trigger (a11y).
      setReplyParentId(null);
      const trigger = replyTriggerRef.current;
      if (trigger) {
        requestAnimationFrame(() => trigger.focus());
      }
    },
    [currentUser, dispatch, onAddComment],
  );

  const cancelReply = useCallback(() => {
    setReplyParentId(null);
    const trigger = replyTriggerRef.current;
    if (trigger) {
      requestAnimationFrame(() => trigger.focus());
    }
  }, []);

  const openReply = useCallback(
    (parentId: string, triggerEl: HTMLElement | null) => {
      replyTriggerRef.current = triggerEl;
      setReplyParentId(parentId);
    },
    [],
  );

  const handleLoadMore = useCallback(async () => {
    if (!onLoadMore || isLoadingMore) return;
    setIsLoadingMore(true);
    try {
      const nextPage = currentPage + 1;
      const result = await onLoadMore(nextPage);
      dispatch({ kind: "append-page", comments: result });
      setCurrentPage(nextPage);
      setHasMore(result.length === pageSize);
    } finally {
      setIsLoadingMore(false);
    }
  }, [onLoadMore, isLoadingMore, currentPage, pageSize, dispatch]);

  // ─── Render ───────────────────────────────────────────────────────────────

  const showEmpty = comments.length === 0 && !subscribe;

  return (
    <div className={cn("flex flex-col gap-3", className)}>
      {showEmpty ? (
        emptyState ?? <CommentEmptyState message={labels.emptyState} />
      ) : (
        <ul className="flex flex-col gap-3">
          {comments.map((c) => (
            <li key={c.id}>
              <CommentNode
                comment={c}
                depth={0}
                maxDepth={maxDepth}
                indentPx={indentPx}
                variant={variant}
                bodyMaxLines={bodyMaxLines}
                currentUser={currentUser}
                labels={labels}
                format={format}
                isReplyOpen={replyParentId === c.id}
                onOpenReply={openReply}
                onCancelReply={cancelReply}
                onSubmitReply={submitReply}
                onLike={handleLike}
                onDelete={handleDelete}
                onReport={handleReport}
                onReportPresent={!!onReportComment}
                commentActions={commentActions}
                renderNode={renderNode}
                renderViewReplies={renderViewReplies}
                composerMinRows={composerMinRows}
                composerMaxRows={composerMaxRows}
                submitOnEnter={submitOnEnter}
                composerClassName={composerClassName}
                nodeClassName={nodeClassName}
              />
            </li>
          ))}
        </ul>
      )}

      {hasMore && onLoadMore ? (
        <button
          type="button"
          onClick={() => {
            void handleLoadMore();
          }}
          disabled={isLoadingMore}
          className="self-center rounded-md px-3 py-1 text-xs font-medium text-muted-foreground transition-colors hover:text-foreground disabled:opacity-50"
        >
          {isLoadingMore ? `${labels.loadMore}…` : labels.loadMore}
        </button>
      ) : null}

      {currentUser ? (
        renderComposer ? (
          renderComposer(
            { value: "", isReply: false, isSubmitting: false },
            {
              setValue: () => {},
              submit: async () => {},
              cancel: () => {},
            },
          )
        ) : (
          <CommentComposer
            ref={composerRef}
            currentUser={currentUser}
            placeholder={labels.composerPlaceholder}
            onSubmit={submitTopLevel}
            submitOnEnter={submitOnEnter}
            minRows={composerMinRows}
            maxRows={composerMaxRows}
            className={composerClassName}
            labels={labels}
          />
        )
      ) : (
        composerEmptyState
      )}
    </div>
  );
}

const CommentThread01 = memo(CommentThread01Inner);
CommentThread01.displayName = "CommentThread01";

export { CommentThread01 };

export { CommentThread01 } from "./comment-thread-01";

export {
  CommentComposer,
  type CommentComposerProps,
  type CommentComposerHandle,
} from "./parts/comment-composer";

export {
  commentReducer,
  useCommentState,
  type UseCommentStateOptions,
  type UseCommentStateResult,
} from "./hooks/use-comment-state";

export {
  useAutosizeTextarea,
  type UseAutosizeTextareaOptions,
} from "./hooks/use-autosize-textarea";

export { defaultRelativeTime, toDate } from "./lib/format-time";

export type {
  Comment,
  CommentThread01Props,
  CommentThread01Handle,
  CommentThread01Variant,
  CommentThreadLabels,
  CommentThreadCurrentUser,
  CommentNodeHelpers,
  CommentComposerState,
  CommentComposerHelpers,
  CommentMenuItem,
  CommentDelta,
  CommentLocalAction,
  Subscribe,
  Unsubscribe,
} from "./types";

export { DEFAULT_COMMENT_THREAD_LABELS } from "./types";

export { meta } from "./meta";

import type { ReactNode } from "react";

export type CommentThread01Variant = "default" | "compact";

export interface Comment {
  id: string;
  author: {
    id: string;
    name: string;
    username?: string;
    avatar?: string;
  };
  content: string;
  createdAt: Date | string | number;
  likes: number;
  isLiked?: boolean;
  replies?: Comment[];
  /** Server-known total. Used as label hint when `replies.length` undercounts. */
  replyCount?: number;
}

export type CommentDelta =
  | { kind: "added"; comment: Comment; parentId?: string }
  | { kind: "edited"; commentId: string; content: string }
  | { kind: "removed"; commentId: string }
  | { kind: "liked"; commentId: string; liked: boolean; count: number };

export type Unsubscribe = () => void;
export type Subscribe<T> = (handler: (delta: T) => void) => Unsubscribe;

export interface CommentMenuItem {
  label: string;
  onClick?: () => void;
  icon?: ReactNode;
  destructive?: boolean;
  disabled?: boolean;
}

export interface CommentThreadCurrentUser {
  id: string;
  name: string;
  avatar?: string;
}

export interface CommentNodeHelpers {
  currentUser?: CommentThreadCurrentUser;
  isOwn: boolean;
  depth: number;
  onLike: (nextLiked: boolean) => void;
  onReply: () => void;
  onDelete: () => void;
  onReport: () => void;
}

export interface CommentComposerState {
  value: string;
  isReply: boolean;
  parentId?: string;
  isSubmitting: boolean;
}

export interface CommentComposerHelpers {
  setValue: (next: string) => void;
  submit: () => Promise<void>;
  cancel: () => void;
}

export interface CommentThreadLabels {
  composerPlaceholder?: string;
  composerSend?: string;
  composerCancel?: string;
  like?: string;
  unlike?: string;
  reply?: string;
  delete?: string;
  report?: string;
  /** Function so consumers pluralize / localize without our help. */
  viewReplies?: (count: number) => string;
  loadMore?: string;
  emptyState?: string;
  signInPrompt?: string;
  /** Override the default English relative-time formatter. */
  formatRelativeTime?: (date: Date, now: Date) => string;
}

export const DEFAULT_COMMENT_THREAD_LABELS: Required<
  Omit<CommentThreadLabels, "formatRelativeTime">
> = {
  composerPlaceholder: "Write a comment…",
  composerSend: "Send",
  composerCancel: "Cancel",
  like: "Like",
  unlike: "Unlike",
  reply: "Reply",
  delete: "Delete",
  report: "Report",
  viewReplies: (count) =>
    `View ${count} ${count === 1 ? "reply" : "replies"}`,
  loadMore: "Load older comments",
  emptyState: "No comments yet — be the first.",
  signInPrompt: "Sign in to comment",
};

export type CommentLocalAction =
  | { kind: "add"; comment: Comment; parentId?: string }
  | { kind: "swap-temp"; tempId: string; real: Comment }
  | { kind: "remove"; commentId: string }
  | { kind: "like-toggle"; commentId: string; nextLiked: boolean }
  | { kind: "patch-content"; commentId: string; content: string }
  | { kind: "subscribe-delta"; delta: CommentDelta }
  | { kind: "append-page"; comments: Comment[] }
  | { kind: "reset"; next: Comment[] };

export interface CommentThread01Props {
  /** Initial comments tree. Component owns it from mount; subsequent prop reference changes are IGNORED. Use the imperative handle's reset() to push updates. */
  comments: Comment[];

  /** Visual variant. Default "default". */
  variant?: CommentThread01Variant;

  /** Viewer identity. Drives composer avatar + isOwn check on default kebab. Absent → composer hidden, composerEmptyState rendered. */
  currentUser?: CommentThreadCurrentUser;

  /** Initial render depth cap. Past this, "view N replies" inline-expands. Default 2. */
  maxDepth?: number;

  /** Pixels of indent per depth level. Default 24. */
  indentPx?: number;

  /** Body line clamp via expandable-text-01. Default 4 (default variant) / 2 (compact). */
  bodyMaxLines?: number;

  /** Composer autosize bounds. Defaults: 1 / 6. */
  composerMinRows?: number;
  composerMaxRows?: number;

  /** Default true — Enter submits, Shift+Enter newline. */
  submitOnEnter?: boolean;

  /** First page size (controls when "Load older comments" button appears). Default 10. */
  pageSize?: number;

  /** Realtime delta stream. Identity-stable required. */
  subscribe?: Subscribe<CommentDelta>;
  /** Fires for every delta the subscription emits. */
  onSubscribeDelta?: (delta: CommentDelta) => void;

  /** Fired after optimistic add. If returned a Comment, the temp comment is swapped for the real one. */
  onAddComment?: (
    content: string,
    parentId?: string,
  ) => Promise<Comment | void> | Comment | void;
  /** Fired after optimistic like flip. */
  onLikeComment?: (commentId: string, nextLiked: boolean) => void;
  /** Fired after optimistic delete. */
  onDeleteComment?: (commentId: string) => void;
  /** Fired on Report kebab click. If omitted, Report item is hidden. */
  onReportComment?: (commentId: string) => void;
  /** Fetch next page of older top-level comments. Component appends results. */
  onLoadMore?: (page: number) => Promise<Comment[]>;

  /** Override the default kebab items. Return [] to hide kebab entirely. */
  commentActions?: (
    comment: Comment,
    helpers: {
      currentUser?: CommentThreadCurrentUser;
      isOwn: boolean;
      depth: number;
    },
  ) => CommentMenuItem[];

  /** Full-takeover for the per-row render. Composer below each row (reply mode) is still owned by the thread. */
  renderNode?: (
    comment: Comment,
    depth: number,
    helpers: CommentNodeHelpers,
  ) => ReactNode;

  /** Override the inline-expand "view N replies" link. */
  renderViewReplies?: (parentId: string, count: number) => ReactNode;

  /** Override the bottom composer entirely. */
  renderComposer?: (
    state: CommentComposerState,
    helpers: CommentComposerHelpers,
  ) => ReactNode;

  /** Rendered in place of the bottom composer when currentUser is absent. Pass null to suppress. */
  composerEmptyState?: ReactNode;

  /** Rendered when comments.length === 0 and no realtime is wired. */
  emptyState?: ReactNode;

  labels?: CommentThreadLabels;

  className?: string;
  composerClassName?: string;
  nodeClassName?: string;
}

export interface CommentThread01Handle {
  /** Programmatically focus the bottom composer textarea. */
  focusComposer: () => void;
  /** Programmatically open the inline reply composer for a parent comment. */
  openReply: (parentId: string) => void;
  /** Read the current optimistic comments tree. */
  getCurrentComments: () => Comment[];
  /** Replace the entire tree (controlled-mode escape hatch). */
  reset: (next: Comment[]) => void;
  /** Drive the reducer directly (advanced controlled-mode escape hatch). */
  dispatch: (action: CommentLocalAction) => void;
}

"use client";

import {
  memo,
  useId,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import { cn } from "@/lib/utils";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { ExpandableText01 } from "@/registry/components/data/expandable-text-01";
import { EngagementBar01 } from "@/registry/components/data/engagement-bar-01";
import { CommentKebab } from "./comment-kebab";
import { CommentComposer } from "./comment-composer";
import { ViewRepliesLink } from "./view-replies-link";
import { toDate } from "../lib/format-time";
import type {
  Comment,
  CommentMenuItem,
  CommentNodeHelpers,
  CommentThreadCurrentUser,
  CommentThreadLabels,
} from "../types";

export interface CommentNodeProps {
  comment: Comment;
  depth: number;
  maxDepth: number;
  indentPx: number;
  variant: "default" | "compact";
  bodyMaxLines: number;
  currentUser?: CommentThreadCurrentUser;
  labels: Required<Omit<CommentThreadLabels, "formatRelativeTime">>;
  format: (date: Date, now: Date) => string;
  isReplyOpen: boolean;
  onOpenReply: (parentId: string, triggerEl: HTMLElement | null) => void;
  onCancelReply: () => void;
  onSubmitReply: (content: string, parentId: string) => Promise<void>;
  onLike: (commentId: string, nextLiked: boolean) => void;
  onDelete: (commentId: string) => void;
  onReport: (commentId: string) => void;
  onReportPresent: boolean;
  commentActions?: (
    comment: Comment,
    helpers: {
      currentUser?: CommentThreadCurrentUser;
      isOwn: boolean;
      depth: number;
    },
  ) => CommentMenuItem[];
  renderNode?: (
    comment: Comment,
    depth: number,
    helpers: CommentNodeHelpers,
  ) => ReactNode;
  renderViewReplies?: (parentId: string, count: number) => ReactNode;
  composerMinRows: number;
  composerMaxRows: number;
  submitOnEnter: boolean;
  composerClassName?: string;
  nodeClassName?: string;
  /** Whether this branch's "view N replies" link should be hidden (because the parent already expanded it). */
  forceShowAllReplies?: boolean;
}

function initials(name: string): string {
  return name
    .trim()
    .split(/\s+/)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .slice(0, 2)
    .join("") || "?";
}

function CommentNodeInner(props: CommentNodeProps) {
  const {
    comment,
    depth,
    maxDepth,
    indentPx,
    bodyMaxLines,
    currentUser,
    labels,
    format,
    isReplyOpen,
    onOpenReply,
    onCancelReply,
    onSubmitReply,
    onLike,
    onDelete,
    onReport,
    onReportPresent,
    commentActions,
    renderNode,
    renderViewReplies,
    composerMinRows,
    composerMaxRows,
    submitOnEnter,
    composerClassName,
    nodeClassName,
    forceShowAllReplies = false,
  } = props;

  const baseId = useId();
  const authorId = `${baseId}-author`;
  const repliesId = `${baseId}-replies`;

  const [expandedToDepth, setExpandedToDepth] = useState(0);

  const isOwn = !!currentUser && currentUser.id === comment.author.id;

  // helpers passed to renderNode slot — onReply receives null trigger
  // (slot owners do their own focus-restoration if they care).
  const helpers: CommentNodeHelpers = useMemo(
    () => ({
      currentUser,
      isOwn,
      depth,
      onLike: (nextLiked: boolean) => onLike(comment.id, nextLiked),
      onReply: () => onOpenReply(comment.id, null),
      onDelete: () => onDelete(comment.id),
      onReport: () => onReport(comment.id),
    }),
    [
      currentUser,
      isOwn,
      depth,
      comment.id,
      onLike,
      onOpenReply,
      onDelete,
      onReport,
    ],
  );

  // ─── Render takeover ──────────────────────────────────────────────────────
  if (renderNode) {
    return (
      <>
        {renderNode(comment, depth, helpers)}
        {isReplyOpen && currentUser ? (
          <div className="ml-10 mt-2">
            <CommentComposer
              currentUser={currentUser}
              placeholder={labels.composerPlaceholder}
              onSubmit={(content) => onSubmitReply(content, comment.id)}
              onCancel={onCancelReply}
              submitOnEnter={submitOnEnter}
              minRows={composerMinRows}
              maxRows={composerMaxRows}
              className={composerClassName}
              labels={labels}
              ariaLabel={`Reply to ${comment.author.name}`}
              autoFocus
            />
          </div>
        ) : null}
      </>
    );
  }

  // ─── Reply visibility logic ───────────────────────────────────────────────
  const totalReplies = comment.replies?.length ?? 0;
  const renderableDepth = forceShowAllReplies
    ? Number.POSITIVE_INFINITY
    : maxDepth + expandedToDepth;
  const showReplies = totalReplies > 0 && depth + 1 <= renderableDepth;
  const hiddenAtBoundary = !showReplies && totalReplies > 0;
  const hiddenCountLabel = comment.replyCount ?? totalReplies;

  // ─── Default render ───────────────────────────────────────────────────────
  return (
    <article
      role="article"
      aria-labelledby={authorId}
      style={depth > 0 ? { paddingLeft: depth * indentPx } : undefined}
      className={cn("group flex items-start gap-2", nodeClassName)}
    >
      <Avatar className="h-8 w-8 shrink-0">
        {comment.author.avatar ? (
          <AvatarImage src={comment.author.avatar} alt="" />
        ) : null}
        <AvatarFallback>{initials(comment.author.name)}</AvatarFallback>
      </Avatar>

      <div className="min-w-0 flex-1">
        <div className="rounded-xl bg-muted/50 px-3 py-2">
          <div className="flex items-center gap-1">
            <span id={authorId} className="text-sm font-semibold">
              {comment.author.name}
            </span>
            {comment.author.username ? (
              <span className="text-xs text-muted-foreground">
                @{comment.author.username}
              </span>
            ) : null}
          </div>
          <ExpandableText01
            content={comment.content}
            maxLines={bodyMaxLines}
            contentClassName="text-sm mt-0.5"
          />
        </div>

        <div className="mt-1 flex items-center gap-3 px-1">
          <span className="text-xs text-muted-foreground">
            {format(toDate(comment.createdAt), new Date())}
          </span>
          <EngagementBar01
            variant="compact"
            actions={[
              {
                kind: "like",
                count: comment.likes,
                liked: comment.isLiked ?? false,
                onToggle: helpers.onLike,
              },
            ]}
          />
          {currentUser ? (
            <button
              type="button"
              onClick={(e) => onOpenReply(comment.id, e.currentTarget)}
              className="text-xs font-medium text-muted-foreground transition-colors hover:text-foreground"
            >
              {labels.reply}
            </button>
          ) : null}
        </div>

        {/* Recursive replies */}
        {showReplies && comment.replies ? (
          <ul id={repliesId} className="mt-2 flex flex-col gap-3">
            {comment.replies.map((reply) => (
              <li key={reply.id}>
                <CommentNode
                  {...props}
                  comment={reply}
                  depth={depth + 1}
                  forceShowAllReplies={forceShowAllReplies}
                />
              </li>
            ))}
          </ul>
        ) : null}

        {/* Past maxDepth — view-N-replies link (default inline-expand) */}
        {hiddenAtBoundary
          ? renderViewReplies
            ? renderViewReplies(comment.id, hiddenCountLabel)
            : (
                <ViewRepliesLink
                  count={hiddenCountLabel}
                  label={labels.viewReplies(hiddenCountLabel)}
                  controlsId={repliesId}
                  onExpand={() => setExpandedToDepth((d) => d + 1)}
                />
              )
          : null}

        {/* Inline reply composer */}
        {isReplyOpen && currentUser ? (
          <div className="mt-2">
            <CommentComposer
              currentUser={currentUser}
              placeholder={labels.composerPlaceholder}
              onSubmit={(content) => onSubmitReply(content, comment.id)}
              onCancel={onCancelReply}
              submitOnEnter={submitOnEnter}
              minRows={composerMinRows}
              maxRows={composerMaxRows}
              className={composerClassName}
              labels={labels}
              ariaLabel={`Reply to ${comment.author.name}`}
              autoFocus
            />
          </div>
        ) : null}
      </div>

      <CommentKebab
        comment={comment}
        currentUser={currentUser}
        isOwn={isOwn}
        depth={depth}
        labels={labels}
        onDelete={helpers.onDelete}
        onReport={helpers.onReport}
