"use client";

import { useEffect, useReducer, useRef } from "react";
import type {
  Comment,
  CommentDelta,
  CommentLocalAction,
  Subscribe,
} from "../types";

// ─── Pure tree-walk helpers ──────────────────────────────────────────────────

function findAndPatch(
  tree: Comment[],
  predicate: (c: Comment) => boolean,
  patch: (c: Comment) => Comment,
): Comment[] {
  let mutated = false;
  const next = tree.map((c) => {
    if (predicate(c)) {
      const patched = patch(c);
      if (patched !== c) mutated = true;
      return patched;
    }
    if (c.replies && c.replies.length > 0) {
      const replies = findAndPatch(c.replies, predicate, patch);
      if (replies !== c.replies) {
        mutated = true;
        return { ...c, replies };
      }
    }
    return c;
  });
  return mutated ? next : tree;
}

function pruneById(tree: Comment[], id: string): Comment[] {
  let mutated = false;
  const next: Comment[] = [];
  for (const c of tree) {
    if (c.id === id) {
      mutated = true;
      continue;
    }
    if (c.replies && c.replies.length > 0) {
      const replies = pruneById(c.replies, id);
      if (replies !== c.replies) {
        mutated = true;
        next.push({ ...c, replies });
        continue;
      }
    }
    next.push(c);
  }
  return mutated ? next : tree;
}

function insertReply(
  tree: Comment[],
  parentId: string,
  comment: Comment,
): Comment[] {
  return findAndPatch(
    tree,
    (c) => c.id === parentId,
    (c) => ({ ...c, replies: [...(c.replies ?? []), comment] }),
  );
}

// ─── Reducer ─────────────────────────────────────────────────────────────────

/** Pure reducer — exported for hosts driving their own state. */
export function commentReducer(
  state: Comment[],
  action: CommentLocalAction,
): Comment[] {
  switch (action.kind) {
    case "add":
      if (action.parentId) {
        return insertReply(state, action.parentId, action.comment);
      }
      // Head insertion for top-level (newest first; pairs with load-older at bottom).
      return [action.comment, ...state];

    case "swap-temp":
      return findAndPatch(
        state,
        (c) => c.id === action.tempId,
        () => action.real,
      );

    case "remove":
      return pruneById(state, action.commentId);

    case "like-toggle":
      return findAndPatch(
        state,
        (c) => c.id === action.commentId,
        (c) => {
          if (c.isLiked === action.nextLiked) return c; // idempotent
          return {
            ...c,
            isLiked: action.nextLiked,
            likes: action.nextLiked
              ? c.likes + 1
              : Math.max(0, c.likes - 1),
          };
        },
      );

    case "patch-content":
      return findAndPatch(
        state,
        (c) => c.id === action.commentId,
        (c) => ({ ...c, content: action.content }),
      );

    case "subscribe-delta": {
      const d = action.delta;
      switch (d.kind) {
        case "added":
          return d.parentId
            ? insertReply(state, d.parentId, d.comment)
            : [d.comment, ...state];
        case "edited":
          return findAndPatch(
            state,
            (c) => c.id === d.commentId,
            (c) => ({ ...c, content: d.content }),
          );
        case "removed":
          return pruneById(state, d.commentId);
        case "liked":
          return findAndPatch(
            state,
            (c) => c.id === d.commentId,
            (c) => ({ ...c, isLiked: d.liked, likes: d.count }),
          );
      }
      return state;
    }

    case "append-page":
      return [...state, ...action.comments];

    case "reset":
      return action.next;
  }
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export interface UseCommentStateOptions {
  /** Captured ON MOUNT only — subsequent prop changes are ignored. */
  initialComments: Comment[];
  subscribe?: Subscribe<CommentDelta>;
  onSubscribeDelta?: (delta: CommentDelta) => void;
}

export interface UseCommentStateResult {
  comments: Comment[];
  dispatch: React.Dispatch<CommentLocalAction>;
}

/**
 * Wires:
 *  - useReducer over commentReducer
 *  - subscription effect that fires onSubscribeDelta and patches state
 *
 * onSubscribeDelta is mirrored to a ref so the subscription effect re-runs
 * ONLY on `subscribe` identity change — same shape as engagement-bar-01.
 */
export function useCommentState(
  opts: UseCommentStateOptions,
): UseCommentStateResult {
  const [comments, dispatch] = useReducer(
    commentReducer,
    opts.initialComments,
  );

  const onSubscribeDeltaRef = useRef(opts.onSubscribeDelta);
  useEffect(() => {
    onSubscribeDeltaRef.current = opts.onSubscribeDelta;
  });

  const subscribe = opts.subscribe;
  useEffect(() => {
    if (!subscribe) return;
    const unsub = subscribe((delta) => {
      onSubscribeDeltaRef.current?.(delta);
      dispatch({ kind: "subscribe-delta", delta });
    });
    return unsub;
  }, [subscribe]);

  return { comments, dispatch };
}

"use client";

import { useLayoutEffect, useRef } from "react";

export interface UseAutosizeTextareaOptions {
  minRows?: number;
  maxRows?: number;
}

/**
 * Resizes a <textarea> to fit its content within [minRows, maxRows] line bounds.
 * Pure DOM mutation in useLayoutEffect — no React state, no rerender.
 *
 * Returns a ref to attach to the textarea element.
 */
export function useAutosizeTextarea(
  value: string,
  opts: UseAutosizeTextareaOptions = {},
) {
  const { minRows = 1, maxRows = 6 } = opts;
  const ref = useRef<HTMLTextAreaElement | null>(null);

  useLayoutEffect(() => {
    const el = ref.current;
    if (!el) return;
    // Reset to "auto" so scrollHeight reflects natural content height.
    el.style.height = "auto";
    const computed = window.getComputedStyle(el);
    const lineHeight = parseFloat(computed.lineHeight) || 20;
    const paddingY =
      parseFloat(computed.paddingTop) + parseFloat(computed.paddingBottom);
    const min = lineHeight * minRows + paddingY;
    const max = lineHeight * maxRows + paddingY;
    const next = Math.min(Math.max(el.scrollHeight, min), max);
    el.style.height = `${next}px`;
    // Allow internal scroll only if natural height exceeds maxRows.
    el.style.overflowY = el.scrollHeight > max ? "auto" : "hidden";
  }, [value, minRows, maxRows]);

  return ref;
}

/** Coerces Date | string | number into a Date — matches event-card-01 / progress-timeline-01. */
export function toDate(value: Date | string | number): Date {
  if (value instanceof Date) return value;
  return new Date(value);
}

const MONTHS = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];

/**
 * Default English relative-time formatter for comments. Tighter granularity than
 * content-card-news-01's day-level formatter:
 *   < 1 min     → "Just now"
 *   < 60 min    → "5m"
 *   < 24 hours  → "2h"
 *   < 7 days    → "3d"
 *   < 5 weeks   → "2w"
 *   ≥ 5 weeks   → "March 5"  (or "March 5, 2025" if year differs)
 */
export function defaultRelativeTime(date: Date, now: Date = new Date()): string {
  const diffMs = now.getTime() - date.getTime();
  const diffSec = Math.floor(diffMs / 1000);
  if (diffSec < 60) return "Just now";

  const diffMin = Math.floor(diffSec / 60);
  if (diffMin < 60) return `${diffMin}m`;

  const diffHr = Math.floor(diffMin / 60);
  if (diffHr < 24) return `${diffHr}h`;

  const diffDay = Math.floor(diffHr / 24);
  if (diffDay < 7) return `${diffDay}d`;

  const diffWk = Math.floor(diffDay / 7);
  if (diffWk < 5) return `${diffWk}w`;

  const sameYear = date.getFullYear() === now.getFullYear();
  return sameYear
    ? `${MONTHS[date.getMonth()]} ${date.getDate()}`
    : `${MONTHS[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
}
